import{_ as t,o,c as a,ag as r}from"./chunks/framework.DZKik_R9.js";const p=JSON.parse('{"title":"Module Federation et intégration hôte","description":"","frontmatter":{},"headers":[],"relativePath":"solution/module-federation.md","filePath":"solution/module-federation.md"}'),n={name:"solution/module-federation.md"};function d(i,e,s,c,l,m){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="module-federation-et-integration-hote" tabindex="-1">Module Federation et intégration hôte <a class="header-anchor" href="#module-federation-et-integration-hote" aria-label="Permalink to &quot;Module Federation et intégration hôte&quot;">​</a></h1><h2 id="objectif" tabindex="-1">Objectif <a class="header-anchor" href="#objectif" aria-label="Permalink to &quot;Objectif&quot;">​</a></h2><p>Permettre à un <strong>site hôte</strong> (React, autre stack, bundler Vite/Webpack) de :</p><ol><li>Charger le <strong>remote</strong> déployé depuis <code>abtest-solution</code> (<code>apps/remote</code>).</li><li>Appeler <strong><code>/api/evaluate</code></strong> avec un contexte (cookies, URL, etc.).</li><li>Afficher la <strong>variante</strong> (JS/CSS/composants) retournée par le moteur.</li></ol><h2 id="etapes" tabindex="-1">Étapes <a class="header-anchor" href="#etapes" aria-label="Permalink to &quot;Étapes&quot;">​</a></h2><ol><li><strong>Build</strong> du workspace <code>apps/remote</code> et hébergement statique (CDN, bucket, etc.).</li><li><strong>Déclarer</strong> le remote dans la config Module Federation du hôte (URL du <code>remoteEntry</code> selon build).</li><li><strong>Importer</strong> au runtime les modules exposés (composant, hooks, etc., selon l’API du remote).</li></ol><p>Le dépôt <strong><code>small-webserver</code></strong> illustre une chaîne complète en labo.</p><h2 id="parametres-d-url-remote-abtestslot" tabindex="-1">Paramètres d’URL (remote <code>AbTestSlot</code>) <a class="header-anchor" href="#parametres-d-url-remote-abtestslot" aria-label="Permalink to &quot;Paramètres d’URL (remote `AbTestSlot`)&quot;">​</a></h2><p>Le composant exposé lit notamment :</p><table tabindex="0"><thead><tr><th>Paramètre</th><th>Description</th></tr></thead><tbody><tr><td><code>ab_campaign_id</code></td><td><strong>Nombre</strong> (id campagne 10000–99999).</td></tr><tr><td><code>ab_simulation=1</code></td><td>Active un mode simulation côté API (objet <code>simulation</code> non nul).</td></tr><tr><td><code>ab_variation_id</code></td><td>Optionnel : <strong>nombre</strong> (id de variation) pour forcer une variante en démo.</td></tr></tbody></table><p>Variable d’environnement côté build : <code>VITE_ABTEST_API_URL</code> (sinon <code>http://localhost:5002</code> par défaut en dev).</p><h2 id="contexte-navigateur" tabindex="-1">Contexte navigateur <a class="header-anchor" href="#contexte-navigateur" aria-label="Permalink to &quot;Contexte navigateur&quot;">​</a></h2><p>Le remote alimente notamment :</p><table tabindex="0"><thead><tr><th>Champ dans <code>context</code></th><th>Rôle</th></tr></thead><tbody><tr><td><code>cookies</code></td><td>Objet clé → valeur ; consentement (<code>consent-config</code>) et règles segment <code>cookie</code>.</td></tr><tr><td><code>visitorType</code></td><td><code>new</code> | <code>returning</code> (souvent via cookie démo <code>abtest_returning</code>).</td></tr></tbody></table><p><strong>Géo</strong> (<code>country</code>, <code>region</code>, <code>city</code>) : en général injectée par <strong>BFF</strong>, <strong>edge</strong> ou <strong>CDN</strong>, pas uniquement par le navigateur — voir <a href="./campaigns-segments/segments#contexte-usercontext">Règles et contexte</a>.</p><p>Voir <a href="./campaigns-segments/segments">Segments</a> et <a href="./consent">Consentement</a>.</p>',16)])])}const g=t(n,[["render",d]]);export{p as __pageData,g as default};
